import{_ as r,o as t,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"🥇 黃金追蹤日報 — 2026年5月27日（週三）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-05-27.md","filePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-05-27.md"}'),i={name:"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-05-27.md"};function l(s,e,n,d,h,c){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="🥇-黃金追蹤日報-—-2026年5月27日-週三" tabindex="-1">🥇 黃金追蹤日報 — 2026年5月27日（週三） <a class="header-anchor" href="#🥇-黃金追蹤日報-—-2026年5月27日-週三" aria-label="Permalink to &quot;🥇 黃金追蹤日報 — 2026年5月27日（週三）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：2026-05-27 05:00 TST（2026-05-26 21:00 UTC） <strong>昨日敘事延續</strong>：美伊和談僵局持續 → 今日無突破，荷莫茲海峽仍處半封鎖；美元指數微跌支撑金價；Fed降息時程延後壓力與地緣風險溢價角力</p></blockquote><hr><h2 id="🔍-數據驗證報告" tabindex="-1">🔍 數據驗證報告 <a class="header-anchor" href="#🔍-數據驗證報告" aria-label="Permalink to &quot;🔍 數據驗證報告&quot;">​</a></h2><h3 id="xau-usd-vs-comex-期貨交叉驗證" tabindex="-1">XAU/USD vs COMEX 期貨交叉驗證 <a class="header-anchor" href="#xau-usd-vs-comex-期貨交叉驗證" aria-label="Permalink to &quot;XAU/USD vs COMEX 期貨交叉驗證&quot;">​</a></h3><table tabindex="0"><thead><tr><th>來源</th><th>報價</th><th>說明</th></tr></thead><tbody><tr><td>TradingEconomics (XAU/USD spot)</td><td>~$4,524/oz</td><td>Bid $4,524.25 / Ask $4,524.55</td></tr><tr><td>Markets.com (spot)</td><td>~$4,495–$4,540</td><td>Range during 5/26 trading</td></tr><tr><td>MQL5 (spot quote)</td><td>Low $4,500.73 / High $4,580.50</td><td>Daily range 5/26</td></tr></tbody></table><p><strong>驗證結論</strong>：多來源一致性良好，價差不超過 $85（高低點跨度），在正常範圍內。取可信值 <strong>$4,524/oz</strong>。</p><p>📎 來源：<a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://vertexaisearch.cloud.google.com/grounding-api-redirect/AUZIYQFhQPMoK5Kvc9gFx1lhyYJTEF14PrKtDVC97aG-T54jVXRIqCSAXRGfL_syT8gbFwhd9UT6CGBmzeYeslZvTMeJ_3E3U8k-SXSKdUSE6zeqH0jE_1s0nbh2qXkLkMRTETfnR0cNgkOB1spzdNG3gnI=" target="_blank" rel="noreferrer">Markets.com</a> · <a href="https://www.mql5.com/en/quotes/metals/xauusd" target="_blank" rel="noreferrer">MQL5</a> （T: 05:00 TST）</p><hr><h2 id="📊-10項指標檢查" tabindex="-1">📊 10項指標檢查 <a class="header-anchor" href="#📊-10項指標檢查" aria-label="Permalink to &quot;📊 10項指標檢查&quot;">​</a></h2><h3 id="指標1️⃣-comex-黃金現貨價格-—-🔴-下跌約-1-6" tabindex="-1">指標1️⃣ COMEX 黃金現貨價格 — 🔴 下跌約 1.6% <a class="header-anchor" href="#指標1️⃣-comex-黃金現貨價格-—-🔴-下跌約-1-6" aria-label="Permalink to &quot;指標1️⃣ COMEX 黃金現貨價格 — 🔴 下跌約 1.6%&quot;">​</a></h3><p><strong>最新報價</strong>：~$4,524/oz</p><ul><li>日變動：-0.99%（5/26）</li><li>日間低點：$4,500.73 / 高點：$4,580.50</li><li>LBMA Q1 2026 PM price 均價創紀錄 $4,873/oz，1月曾觸及歷史高點 $5,405/oz 後回調</li></ul><p>📎 來源：TradingEconomics (2026-05-26) （T: 05:00 TST）</p><hr><h3 id="指標2️⃣-10年期-tips-實質利率-—-🟢-持平偏強" tabindex="-1">指標2️⃣ 10年期 TIPS 實質利率 — 🟢 持平偏強 <a class="header-anchor" href="#指標2️⃣-10年期-tips-實質利率-—-🟢-持平偏強" aria-label="Permalink to &quot;指標2️⃣ 10年期 TIPS 實質利率 — 🟢 持平偏強&quot;">​</a></h3><p><strong>最新報價</strong>：~2.10–2.17%</p><ul><li>5/26 收盤持穩於 2.10%</li><li>5/21 為 2.18%，整體呈緩步下行趨勢</li><li>5/24 10Y TIPS 拍賣收益率 2.169%</li></ul><p>實質利率下行有利金價，但幅度有限，顯示市場對通膨預期已部分反映。</p><p>📎 來源：<a href="https://tradingeconomics.com/united-states/10-year-tips-yield" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.macrotrends.net/3010/10-year-tips-yield" target="_blank" rel="noreferrer">Macrotrends</a> （T: 05:00 TST）</p><hr><h3 id="指標3️⃣-美元指數-dxy-—-🟢-微跌支撐金價" tabindex="-1">指標3️⃣ 美元指數 DXY — 🟢 微跌支撐金價 <a class="header-anchor" href="#指標3️⃣-美元指數-dxy-—-🟢-微跌支撐金價" aria-label="Permalink to &quot;指標3️⃣ 美元指數 DXY — 🟢 微跌支撐金價&quot;">​</a></h3><p><strong>最新報價</strong>：~99.10</p><ul><li>波動區間：99.09–99.167</li><li>24小時變動：+0.14% 或 -0.07%（不同來源略有差異）</li><li>受中東局勢及 Fed 政策預期雙向拉扯</li></ul><p>美元走弱有助於以美元計价的黃金上漲。</p><p>📎 來源：<a href="https://www.tradingview.com/symbols/TVC-DXY/" target="_blank" rel="noreferrer">TradingView</a> · <a href="https://www.fxstreet.com/currencies/us-dollar-index" target="_blank" rel="noreferrer">FXStreet</a> （T: 05:00 TST）</p><hr><h3 id="指標4️⃣-聯準會利率決策-點陣圖-—-🟡-維持觀察" tabindex="-1">指標4️⃣ 聯準會利率決策 + 點陣圖 — 🟡 維持觀察 <a class="header-anchor" href="#指標4️⃣-聯準會利率決策-點陣圖-—-🟡-維持觀察" aria-label="Permalink to &quot;指標4️⃣ 聯準會利率決策 + 點陣圖 — 🟡 維持觀察&quot;">​</a></h3><p>無最新 FOMC 會議。重點關注日本央行總裁 Ueda 今日演說、澳洲 CPI、紐西蘭 RBNZ 利率決議等全球央行動態。Fed 降息時程因中東衝突影響通膨而存在不確定性。</p><p>📎 來源：<a href="https://apnews.com/world-news" target="_blank" rel="noreferrer">AP News</a> （T: 05:00 TST）</p><hr><h3 id="指標5️⃣-央行購金數據-—-🟢-持續買進" tabindex="-1">指標5️⃣ 央行購金數據 — 🟢 持續買進 <a class="header-anchor" href="#指標5️⃣-央行購金數據-—-🟢-持續買進" aria-label="Permalink to &quot;指標5️⃣ 央行購金數據 — 🟢 持續買進&quot;">​</a></h3><p>Q1 2026 淨購金量 <strong>244 公噸</strong>，同比增 3%。波蘭和烏茲別克為主要買家。WGC 預測 2026 年全年央行購金約 850 公噸。</p><p>📎 來源：<a href="https://www.gold.org/goldhub/research/gold-demand-trends/gold-demand-trends-q1-2026" target="_blank" rel="noreferrer">World Gold Council</a> （T: 05:00 TST）</p><hr><h3 id="指標6️⃣-地緣風險事件-—-🔴-持續升溫" tabindex="-1">指標6️⃣ 地緣風險事件 — 🔴 持續升溫 <a class="header-anchor" href="#指標6️⃣-地緣風險事件-—-🔴-持續升溫" aria-label="Permalink to &quot;指標6️⃣ 地緣風險事件 — 🔴 持續升溫&quot;">​</a></h3><p>美伊和平談判無重大突破。特朗普表態不急於達成協議，伊朗稱「協議不即將實現」。以色列軍方與真主黨在黎巴嫩繼續交戰。俄羅斯持續攻擊烏克蘭。全球地緣政治風險溢價維持高位。</p><p>📎 來源：<a href="https://www.wsls.com/news/politics/2026/05/26/the-latest-iran-deal-progress-is-murky-after-us-military-says-it-carried-out-self-defense-strikes/" target="_blank" rel="noreferrer">WSLS</a> · <a href="https://www.aljazeera.com/tag/politics/" target="_blank" rel="noreferrer">Al Jazeera</a> （T: 05:00 TST）</p><hr><h3 id="指標7️⃣-通膨數據-cpi-pce-—-🟡-待更新" tabindex="-1">指標7️⃣ 通膨數據（CPI/PCE） — 🟡 待更新 <a class="header-anchor" href="#指標7️⃣-通膨數據-cpi-pce-—-🟡-待更新" aria-label="Permalink to &quot;指標7️⃣ 通膨數據（CPI/PCE） — 🟡 待更新&quot;">​</a></h3><p>今日澳洲 CPI 發布為關鍵看點。美國 PCE/CPI 等待下次公布。中東衝突推升能源及食品價格可能推高全球通膨預期。</p><p>📎 來源：<a href="https://apnews.com/world-news" target="_blank" rel="noreferrer">AP News</a> （T: 05:00 TST）</p><hr><h3 id="指標8️⃣-黃金-etf-持倉量-—-🟢-穩定" tabindex="-1">指標8️⃣ 黃金 ETF 持倉量 — 🟢 穩定 <a class="header-anchor" href="#指標8️⃣-黃金-etf-持倉量-—-🟢-穩定" aria-label="Permalink to &quot;指標8️⃣ 黃金 ETF 持倉量 — 🟢 穩定&quot;">​</a></h3><p>iShares Physical Gold ETC (SGLN) 信托持有量截至 5/25 為 260.02 公噸。SPDR Gold Shares (GLD) 持有比例 100.04%。整體 ETF 持倉穩定。</p><p>📎 來源：<a href="https://seekingalpha.com/symbol/GLD" target="_blank" rel="noreferrer">Seeking Alpha</a> · <a href="https://www.ishares.com/uk/individual/en/products/258441/ishares-physical-gold-etc-fund" target="_blank" rel="noreferrer">iShares</a> （T: 05:00 TST）</p><hr><h3 id="指標9️⃣-黃金礦產供應-—-🟢-無重大變化" tabindex="-1">指標9️⃣ 黃金礦產供應 — 🟢 無重大變化 <a class="header-anchor" href="#指標9️⃣-黃金礦產供應-—-🟢-無重大變化" aria-label="Permalink to &quot;指標9️⃣ 黃金礦產供應 — 🟢 無重大變化&quot;">​</a></h3><p>無新發布的季度供應鏈報告。礦產供應保持相對穩定。</p><p>📎 來源：WGC Quarterly （T: 05:00 TST）</p><hr><h3 id="指標🔟-大型投行金價預測-—-🟡-維持不變" tabindex="-1">指標🔟 大型投行金價預測 — 🟡 維持不變 <a class="header-anchor" href="#指標🔟-大型投行金價預測-—-🟡-維持不變" aria-label="Permalink to &quot;指標🔟 大型投行金價預測 — 🟡 維持不變&quot;">​</a></h3><table tabindex="0"><thead><tr><th>機構</th><th>目標價</th><th>時間</th><th>來源</th></tr></thead><tbody><tr><td>Goldman Sachs</td><td>$5,400/oz</td><td>2026年底</td><td><a href="https://www.thestreet.com/investing/goldman-sachs-has-crucial-message-for-gold-investors-in-2026" target="_blank" rel="noreferrer">TheStreet</a></td></tr><tr><td>J.P. Morgan</td><td>$5,055/oz (Q4 2026), $5,400/oz (EOY 2027)</td><td>Q4 2026</td><td><a href="https://www.jpmorgan.com/insights/global-research/commodities/gold-prices" target="_blank" rel="noreferrer">J.P. Morgan</a></td></tr><tr><td>WisdomTree</td><td>&gt;$4,500 (Q3 2026 base), &gt;$5,000 (bull case)</td><td>Q3 2026</td><td><a href="https://www.wisdomtree.com/investments/-/media/us-media-files/documents/resource-library/market-insights/wisdomtree-commentary/gold-outlook-to-q3-2026.pdf" target="_blank" rel="noreferrer">WisdomTree PDF</a></td></tr></tbody></table><p>📎 來源：<a href="https://www.goldrepublic.com/en-us/gold-price/forecast" target="_blank" rel="noreferrer">GoldRepublic</a> · <a href="https://www.kitco.com/news/article/2026-05-19/central-banks-are-buying-more-gold-expected-and-purchases-will-increase" target="_blank" rel="noreferrer">Kitco</a> （T: 05:00 TST）</p><hr><h2 id="📰-黃金即時新聞-5-則" tabindex="-1">📰 黃金即時新聞 5 則 <a class="header-anchor" href="#📰-黃金即時新聞-5-則" aria-label="Permalink to &quot;📰 黃金即時新聞 5 則&quot;">​</a></h2><ol><li><p><strong>[5/19] 央行黃金購買量預計增加 — WGC 年度預測 850 公噸</strong> Central banks are buying more gold than expected, with purchases set to increase in 2026. WGC forecasts ~850 tonnes for full year. 📎 <a href="https://www.kitco.com/news/article/2026-05-19/central-banks-are-buying-more-gold-expected-and-purchases-will-increase" target="_blank" rel="noreferrer">Kitco</a></p></li><li><p><strong>[5/19] 高盛重申 $5,400 Targets — 結構性牛市未改</strong> Goldman Sachs reaffirmed $5,400/oz price target by end of 2026, citing geopolitical risk premium and central bank demand. 📎 <a href="https://www.thestreet.com/investing/goldman-sachs-has-crucial-message-for-gold-investors-in-2026" target="_blank" rel="noreferrer">TheStreet</a></p></li><li><p><strong>[5/26] 金價小幅回落 — 和美伊和談預期帶動風險偏好回升</strong> Gold dipped ~1% as peace negotiation expectations reduced safe-haven bid, but remained well above $4,500. 📎 <a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">TradingEconomics</a></p></li><li><p><strong>[5/18] 白銀跟隨黃金走勢 — 當日均價 $76.15</strong> Silver declined 2.48% from prior session but YTD performance remains positive at +6.80%. 📎 <a href="https://www.forbes.com/advisor/investing/silver-price/" target="_blank" rel="noreferrer">Forbes Advisor</a></p></li><li><p><strong>[5/26] 地緣政治風險支撐金價底線</strong> Despite peace talk hopes, US military continues &quot;self-defense&quot; strikes against Iranian positions, keeping risk premium elevated. 📎 <a href="https://www.wsls.com/news/politics/2026/05/26/the-latest-iran-deal-progress-is-murky-after-us-military-says-it-carried-out-self-defense-strikes/" target="_blank" rel="noreferrer">WSLS</a></p></li></ol><hr><h2 id="📈-連動商品速覽" tabindex="-1">📈 連動商品速覽 <a class="header-anchor" href="#📈-連動商品速覽" aria-label="Permalink to &quot;📈 連動商品速覽&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>最新價</th><th>日變動</th></tr></thead><tbody><tr><td>白銀 (XAG/USD)</td><td>$76.15/oz</td><td>-2.48%</td></tr><tr><td>铂金 (XPT/USD)</td><td>~$1,952–1,963/oz</td><td>+1.20%</td></tr><tr><td>BTC (替代避險資產)</td><td>~$75,767</td><td>-1.89%</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-26): XAU/USD ~$4,524/oz, daily change -0.99%</li><li>TradingEconomics (2026-05-26): 10Y TIPS yield ~2.10%</li><li>TradingView (2026-05-26): DXY ~99.10</li><li>World Gold Council (2026-Q1): Central bank net purchases 244 tonnes</li><li>TheStreet (2026-05-19): Goldman Sachs $5,400 target</li><li>Forbes Advisor (2026-05-26): Silver $76.15</li><li>Kitco (2026-05-19): Central bank gold buying forecast</li><li>WSLS (2026-05-26): Iran deal progress update</li></ol>',63)])])}const m=r(i,[["render",l]]);export{g as __pageData,m as default};
